effect.shader:
vec2 l2s( vec2 v ) {
    return (vec4(v,0.,1.)*acLayerToScreen).xy;
}

float rand(vec2 co){
    return fract(sin(dot(co.xy ,vec2(12.9898,78.233))) * 43758.5453);
}

vec2 rand2(vec2 co){
    return vec2(rand(co), rand(co+vec2(3.7321,9.2517)*vec2(7.1231,6.9377)));
}

float star(vec2 st, float size, float feather) {
    float adjFeather = size * feather;
    return smoothstep(1.0-size-adjFeather,1.0-size,sin(st.x*20.)*sin(st.y*20.));
}

float stars(vec2 st, vec2 parallax, float depth, float size, float feather) {
    float p = 0.;

    size *= 0.001;

    float f = fract(depth);
    float layer = floor(depth);
    //const float layers = 25.;

    for( float i=1.; i<starCount; i+=1.) {
        vec2 uv = st;
        uv *= (i-f)/9.;
        uv += parallax;
        p += star(uv+rand2(vec2(i+layer,2.904)), size, feather) * smoothstep(starCount,1.,i-f);
    }

    return p;
}


void main() {
    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec2 st = acLayerNorm;
    st.y = 1. - st.y;
    st -= 0.5;
    st.x *= acLayerSize.x/acLayerSize.y;

    float p = stars(st, -starParallax/1000., starDepth, starSize, starFeather);

    vec4 adjColor = clamp(vec4(mix(color.rgb+vec3(0.15,0.15,0.15),vec3(1.),0.05)*p*brightness,1.),0.,1.)*p;

    vec4 result;
    if( blendMode==1 ) {
        result = vec4((texColor.rgb/texColor.a)*adjColor.rgb,1.0) * texColor.a;
    } else if( blendMode==2 ) {
        result = vec4( 1.-((1.-(texColor.rgb/texColor.a))*(1.-adjColor.rgb)),1.0) * texColor.a;
    } else if( blendMode==3 ) {
        result = texColor * (1.0-min(p,1.0));
    } else {
        result = adjColor*texColor.a;
        result = texColor*(1.-result.a) + result;
    }
    gl_FragColor = mix(texColor,result,alpha);
}
